mapper.select:
SELECT u.id as userId, u.username, CONCAT(LEFT(u.phone, 3), '****', RIGHT(u.phone, 4)) as phone, CONCAT('****', RIGHT(u.student_teacher_id, 4)) as studentTeacherId, u.campus_email as campusEmail, u.identity_type as identityType, u.auth_status as authStatus, u.auth_result_remark as authResultRemark, u.auth_image_url as authImageUrl, u.credit_score as creditScore, u.avatar_url as avatarUrl, u.birthday, u.create_time as registerTime FROM t_user u WHERE u.is_deleted = 0
AND u.username LIKE CONCAT('%', #{username}, '%')
AND u.auth_status = #{authStatus}
AND u.identity_type = #{identityType}
ORDER BY u.create_time DESC
